#!/bin/bash
# ===================================================================
# MillEntry Central License Server — One-Time Self-Updater Deployment
# Run this ONCE on VPS. After that, all future updates can be done
# from Admin Dashboard → Settings → Server Updates (no SSH needed).
# ===================================================================
set -e
cd /opt/millentry-license || { echo "ERROR: /opt/millentry-license not found"; exit 1; }

echo "[1/5] Backing up current installation..."
BKP="/opt/millentry-license-backup-$(date +%Y%m%d-%H%M%S)"
cp -r /opt/millentry-license "$BKP"
echo "    Backup at: $BKP"

echo "[2/5] Decoding embedded tarball..."
cat > /tmp/cls-v7.b64 <<'__B64__'

__B64__
base64 -d /tmp/cls-v7.b64 > /tmp/cls-v7.tar.gz
ls -la /tmp/cls-v7.tar.gz

echo "[3/5] Extracting & applying (preserving .env, database.json, node_modules)..."
tar -xzf /tmp/cls-v7.tar.gz -C /tmp/
rsync -a --exclude='.env' --exclude='database.json' --exclude='node_modules'   /tmp/central-license-server/ /opt/millentry-license/

echo "[4/5] Installing any new npm dependencies..."
cd /opt/millentry-license
npm install --omit=dev 2>&1 | tail -5 || true

echo "[5/5] Restarting pm2 service..."
pm2 restart millentry-license --update-env || pm2 start server.js --name millentry-license

echo ""
echo "============================================"
echo "✅ Deployment complete!"
echo "Now login at https://admin.9x.design/"
echo "Go to Settings → Server Updates tab"
echo "  - Repo: iamsjtitu/Rice-Mill-latest"
echo "  - Branch: main"
echo "  - (Optional) Add GitHub PAT for private repos"
echo "Click 'Check for Updates' to verify it works."
echo "============================================"
rm -f /tmp/cls-v7.b64 /tmp/cls-v7.tar.gz
rm -rf /tmp/central-license-server
